+    local procedure CalcAdjustedCostFromAppliedEntries(TransferItemLedgEntry: Record "Item Ledger Entry"; AppliedQty: Decimal; var AdjustedCostLCY: Decimal; var AdjustedCostACY: Decimal; var DiscountAmount: Decimal)
+    var
+        ItemApplicationEntry: Record "Item Application Entry";
+        AppliedItemLedgEntry: Record "Item Ledger Entry";
+        TotalCostLCY: Decimal;
+        TotalCostACY: Decimal;
+        TotalDiscount: Decimal;
+        EntryCostLCY: Decimal;
+        EntryCostACY: Decimal;
+        EntryDiscount: Decimal;
+        TotalQty: Decimal;
+    begin
+        // For transfer entries that have outbound applications (negative transfer entries),
+        // calculate the adjusted cost from the original applied inbound entries
+        // This ensures revaluations on the original entries are included
+        if (TransferItemLedgEntry."Entry Type" = TransferItemLedgEntry."Entry Type"::Transfer) and
+           (not TransferItemLedgEntry.Positive)
+        then begin
+            TotalCostLCY := 0;
+            TotalCostACY := 0;
+            TotalDiscount := 0;
+            TotalQty := 0;
+
+            ItemApplicationEntry.SetCurrentKey("Outbound Item Entry No.", "Item Ledger Entry No.");
+            ItemApplicationEntry.SetRange("Outbound Item Entry No.", TransferItemLedgEntry."Entry No.");
+            ItemApplicationEntry.SetFilter("Inbound Item Entry No.", '<>%1', 0);
+            if ItemApplicationEntry.FindSet() then
+                repeat
+                    if AppliedItemLedgEntry.Get(ItemApplicationEntry."Inbound Item Entry No.") then begin
+                        CalcAdjustedCost(AppliedItemLedgEntry, ItemApplicationEntry.Quantity, EntryCostLCY, EntryCostACY, EntryDiscount);
+                        TotalCostLCY += EntryCostLCY;
+                        TotalCostACY += EntryCostACY;
+                        TotalDiscount += EntryDiscount;
+                        TotalQty += ItemApplicationEntry.Quantity;
+                    end;
+                until ItemApplicationEntry.Next() = 0;
+
+            if TotalQty <> 0 then begin
+                AdjustedCostLCY := TotalCostLCY * AppliedQty / TotalQty;
+                AdjustedCostACY := TotalCostACY * AppliedQty / TotalQty;
+                DiscountAmount := TotalDiscount * AppliedQty / TotalQty;
+            end else
+                // Fallback to standard calculation if no applications found
+                CalcAdjustedCost(TransferItemLedgEntry, AppliedQty, AdjustedCostLCY, AdjustedCostACY, DiscountAmount);
+        end else
+            // For non-transfer entries or positive transfer entries, use standard calculation
+            CalcAdjustedCost(TransferItemLedgEntry, AppliedQty, AdjustedCostLCY, AdjustedCostACY, DiscountAmount);
+    end;
+
